#include <stdio.h>

#define KAPACITET 100

struct Osoba {
    char ime[20];
    int godine;
};

int ucitaj(struct Osoba *imenik) {
    FILE *dat = fopen("baza.dat", "rb");
    if (dat == NULL) {
        printf("Greska pri otvaranju datoteke.\n");
        return 0;
    }

    int ucitano = fread(imenik, sizeof(struct Osoba), KAPACITET, dat);

    fclose(dat);
    return ucitano;
}

int main() {
    struct Osoba imenik[KAPACITET];
    int broj;

    broj = ucitaj(imenik);

    if (broj == 0) {
        printf("Nema ucitanih zapisa.\n");
        return 0;
    }

    printf("Ucitano osoba: %d\n", broj);
    printf("-------------------------\n");
    printf("%-20s %s\n", "Ime", "Godine");
    printf("-------------------------\n");

    for (int i = 0; i < broj; i++) {
        printf("%-20s %d\n", imenik[i].ime, imenik[i].godine);
    }

    return 0;
}
